source "$SCRIPT_DIR/_load_env.sh"

CUDA_VISIBLE_DEVICES=1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=7 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --model ViT-L/14  --dataset unc            --vl_hidden_dim 768 --imsize 224 --max_query_len 77 --normalize_before --use_mask_loss  --save_hilora_clip  --mixup_pretrain  --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/mixup_grounding_pretraining_large/mixup/best_checkpoint.pth --eval_set val    --output_dir $OUT_ROOT/mixup_grounding_pretraining_large/unc;
